SELECT comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state, sum(1) AS sample_count, sum(baseline.weight) AS units_count, avg(comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" * baseline.weight * 4.0) AS "electricity.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state JOIN (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline ON baseline.bldg_id = comstock_amy2018_r2_2025_ts_by_state.bldg_id AND baseline.state = comstock_amy2018_r2_2025_ts_by_state.state AND comstock_amy2018_r2_2025_ts_by_state.upgrade = 0 AND baseline.state = 'CO' AND comstock_amy2018_r2_2025_ts_by_state.state = 'CO' WHERE comstock_amy2018_r2_2025_ts_by_state.timestamp IN (timestamp '2018-01-01 12:00:00', timestamp '2018-04-10 12:00:00', timestamp '2018-07-19 12:00:00') GROUP BY 1, 2 ORDER BY 1, 2 -- next snapshot sql -- SELECT comstock_amy2018_r2_2025_ts_by_state.bldg_id, comstock_amy2018_r2_2025_ts_by_state.state, sum(1) AS sample_count, sum(baseline.weight) AS units_count, avg(comstock_amy2018_r2_2025_ts_by_state."out.electricity.total.energy_consumption" * baseline.weight * 4.0) AS "electricity.total.energy_consumption" FROM comstock_amy2018_r2_2025_ts_by_state JOIN (SELECT * FROM comstock_amy2018_r2_2025_md_by_state_and_county_parquet WHERE comstock_amy2018_r2_2025_md_by_state_and_county_parquet.upgrade = 0) AS baseline ON baseline.bldg_id = comstock_amy2018_r2_2025_ts_by_state.bldg_id AND baseline.state = comstock_amy2018_r2_2025_ts_by_state.state AND comstock_amy2018_r2_2025_ts_by_state.upgrade = 0 AND baseline.state = 'CO' AND comstock_amy2018_r2_2025_ts_by_state.state = 'CO' WHERE comstock_amy2018_r2_2025_ts_by_state.timestamp IN (timestamp '2018-01-01 12:15:00', timestamp '2018-04-10 12:15:00', timestamp '2018-07-19 12:15:00') GROUP BY 1, 2 ORDER BY 1, 2